import React, { useState, useEffect, useCallback } from 'react';
import { useTable } from 'react-table';

const MaterialCombiner = ({ apiBaseUrl }) => {
    const [combinedMaterialName, setCombinedMaterialName] = useState('');
    const [materials, setMaterials] = useState([]);
    const [materialChanges, setMaterialChanges] = useState([]);
    const [error, setError] = useState(null);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedMaterials, setSelectedMaterials] = useState([{ materialId: '', multiplier: 1, unitPrice: 0 }]);
    const [combinedMaterials, setCombinedMaterials] = useState([]);

    const fetchAPI = useCallback(async (url, options = {}) => {
        const authToken = sessionStorage.getItem('authToken');
        const response = await fetch(url, {
            ...options,
            headers: {
                ...options.headers,
                'Authorization': `Bearer ${authToken}`,
            },
        });
        if (!response.ok) {
            const errorResponse = await response.json();
            throw new Error(errorResponse.message || `Error fetching ${url}`);
        }
        return response.json();
    }, []);

    const fetchData = useCallback(async () => {
        try {
            const materialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
            const materialChangesData = await fetchAPI(`${apiBaseUrl}/materialchangesAPI`);
            setMaterials(materialData);
            setMaterialChanges(materialChangesData);
        } catch (error) {
            setError(error.message);
        } finally {
            setIsLoading(false);
        }
    }, [fetchAPI, apiBaseUrl]);

    const fetchCombinedMaterials = useCallback(async () => {
        try {
            const data = await fetchAPI(`${apiBaseUrl}/combinedMaterials`);
            setCombinedMaterials(data);
        } catch (error) {
            setError(error.message);
        }
    }, [fetchAPI, apiBaseUrl]); // Add dependencies here

    useEffect(() => {
        fetchData();
        fetchCombinedMaterials();
    }, [fetchData, fetchCombinedMaterials]); // Now fetchCombinedMaterials is stable

    

    const handleMaterialChange = (index, value) => {
        const updatedMaterials = [...selectedMaterials];
        updatedMaterials[index].materialId = value;
    
        const latestPriceEntry = materialChanges
            .filter(mp => mp.material_id === value)
            .sort((a, b) => b.change_id - a.change_id)[0];
    
        updatedMaterials[index].unitPrice = latestPriceEntry ? parseFloat(latestPriceEntry.price) : 0;
    
        setSelectedMaterials(updatedMaterials);
    };

    const handleMultiplierChange = (index, value) => {
        const updatedMaterials = [...selectedMaterials];
        updatedMaterials[index].multiplier = Number(value);
        setSelectedMaterials(updatedMaterials);
    };

    const addMaterial = () => {
        setSelectedMaterials([...selectedMaterials, { materialId: '', multiplier: 1, unitPrice: 0 }]);
    };

    const removeMaterial = (index) => {
        const updatedMaterials = selectedMaterials.filter((_, i) => i !== index);
        setSelectedMaterials(updatedMaterials);
    };

    const saveCombinedMaterial = async () => {
        try {
            const payload = {
                name: combinedMaterialName,
                submaterials: selectedMaterials
            };
            await fetchAPI(`${apiBaseUrl}/saveCombinedMaterial`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(payload)
            });
            alert('Combined material saved successfully!');
            fetchCombinedMaterials(); // Fetch the updated list of combined materials
        } catch (error) {
            alert(`Error: ${error.message}`);
        }
    };
    const handleEdit = (materialId) => {
        // Logic to handle edit (e.g., open a modal or navigate to an edit page)
      };
      
      const handleDelete = async (materialId) => {
        if (window.confirm('Are you sure you want to delete this material?')) {
          try {
            await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`, {
              method: 'DELETE',
            });
            // Refresh the list or remove the item from the state
          } catch (error) {
            alert(`Error: ${error.message}`);
          }
        }
      };
    
      const columns = React.useMemo(
        () => [
            {
                Header: 'Material Name',
                accessor: 'name'
            },
            {
                Header: 'Total Cost',
                accessor: 'totalCost',
                Cell: ({ value }) => `$${value.toFixed(2)}`
            },
            {
                Header: 'Submaterials',
                accessor: 'submaterials',
                Cell: ({ value }) => (
                    <div>
                        {value.map((submaterial, index) => (
                            <div key={index}>
                                Material ID: {submaterial.material_id}, Multiplier: {submaterial.multiplier}, Unit Price: ${submaterial.unitPrice.toFixed(2)}, Total Price: ${(submaterial.multiplier * submaterial.unitPrice).toFixed(2)}
                            </div>
                        ))}
                    </div>
                )
            },
            {
                Header: 'Actions',
                accessor: 'id',
                Cell: ({ value }) => (
                    <div>
                        <button onClick={() => handleEdit(value)}>Edit</button>
                        <button onClick={() => handleDelete(value)}>Delete</button>
                    </div>
                )
            }
        ],
        []
    );

    const data = React.useMemo(
        () => combinedMaterials,
        [combinedMaterials]
    );

    const tableInstance = useTable({ columns, data });

    const {
        getTableProps,
        getTableBodyProps,
        headerGroups,
        rows,
        prepareRow,
    } = tableInstance;

    if (isLoading) return <div>Loading...</div>;
    if (error) return <div>Error: {error}</div>;

    return (
        <div>
            <h2>Combine Materials</h2>
            <h3>Combo Name</h3>
            <input 
                type="text"
                value={combinedMaterialName}
                onChange={(e) => setCombinedMaterialName(e.target.value)}
                placeholder="Enter combined material name"
            />
            {selectedMaterials.map((selection, index) => (
                <div key={index}>
                    <select
                        value={selection.materialId}
                        onChange={(e) => handleMaterialChange(index, e.target.value)}
                    >
                        <option value="">Select Material</option>
                        {materials.map(material => (
                            <option key={material.matid} value={material.matid}>{material.name}</option>
                        ))}
                    </select>
                    <input
                        type="number"
                        value={selection.multiplier}
                        onChange={(e) => handleMultiplierChange(index, e.target.value)}
                    />
                    <span>Unit Price: {selection.unitPrice.toFixed(2)}</span>
                    {selectedMaterials.length > 1 && (
                        <button onClick={() => removeMaterial(index)}>Remove</button>
                    )}
                </div>
            ))}
            <button onClick={addMaterial}>+</button>
            <button onClick={saveCombinedMaterial}>Save Combined Material</button>
            <h3>Combined Materials</h3>
            {combinedMaterials.map(material => (
    <div key={material.id}>
        <h4>{material.name} - Total Cost: {material.totalCost ? material.totalCost.toFixed(2) : '0.00'}</h4>
        <table>
            <thead>
                <tr>
                    <th>Submaterial</th>
                    <th>Multiplier</th>
                    <th>Unit Price</th>
                    <th>Total Price</th>
                </tr>
            </thead>
            <tbody>
                {material.submaterials && material.submaterials.map(submaterial => (
                    <tr key={submaterial.id}>
                        <td>{submaterial.material_id}</td>
                        <td>{submaterial.multiplier}</td>
                        <td>{submaterial.unitPrice ? submaterial.unitPrice.toFixed(2) : '0.00'}</td>
                        <td>{submaterial.unitPrice ? (submaterial.multiplier * submaterial.unitPrice).toFixed(2) : '0.00'}</td>
                    </tr>
                ))}
            </tbody>
        </table>
        <button onClick={() => handleEdit(material.id)}>Edit</button>
        <button onClick={() => handleDelete(material.id)}>Delete</button>
    </div>
))}

        </div>
    );
};

export default MaterialCombiner;
